(()=>{let t=self;t.addEventListener("push",i=>{let n=i.data?.json()??{},e=n.title||"New Notification",o={body:n.body||"Something new happened!",icon:"/globe.svg",badge:"/globe.svg",data:{url:n.url||"/"}};i.waitUntil(t.registration.showNotification(e,o))}),t.addEventListener("notificationclick",i=>{i.notification.close();let n=i.notification.data.url;i.waitUntil(t.clients.matchAll({type:"window",includeUncontrolled:!0}).then(i=>{for(let t=0;t<i.length;t++){let e=i[t];if(e.url===n&&"focus"in e)return e.focus()}if(t.clients.openWindow)return t.clients.openWindow(n)}))})})();